// Canonical bridge key: smaller endpoint first (by x, then y)
export function bridgeKey(island1, island2) {
  const x1 = island1.x, y1 = island1.y;
  const x2 = island2.x, y2 = island2.y;
  if (x1 < x2 || (x1 === x2 && y1 < y2)) {
    return `${x1},${y1},${x2},${y2}`;
  }
  return `${x2},${y2},${x1},${y1}`;
}

// Check if two islands are adjacent (same row/col, no island between them)
export function areAdjacent(islands, from, to) {
  if (from.x !== to.x && from.y !== to.y) return false;
  if (from.x === to.x && from.y === to.y) return false;

  if (from.x === to.x) {
    // Vertical
    const minY = Math.min(from.y, to.y);
    const maxY = Math.max(from.y, to.y);
    for (const isl of islands) {
      if (isl.id === from.id || isl.id === to.id) continue;
      if (isl.x === from.x && isl.y > minY && isl.y < maxY) return false;
    }
  } else {
    // Horizontal
    const minX = Math.min(from.x, to.x);
    const maxX = Math.max(from.x, to.x);
    for (const isl of islands) {
      if (isl.id === from.id || isl.id === to.id) continue;
      if (isl.y === from.y && isl.x > minX && isl.x < maxX) return false;
    }
  }
  return true;
}

// Check if a bridge between from and to would cross any existing bridge
export function wouldCross(islands, bridges, from, to) {
  // Get all existing bridge segments
  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const bx1 = parts[0], by1 = parts[1], bx2 = parts[2], by2 = parts[3];

    // Check crossing: one horizontal one vertical
    if (from.x === to.x) {
      // New bridge is vertical
      if (by1 === by2) {
        // Existing bridge is horizontal
        const crossX = from.x;
        const crossY = by1;
        const minY = Math.min(from.y, to.y);
        const maxY = Math.max(from.y, to.y);
        const minX = Math.min(bx1, bx2);
        const maxX = Math.max(bx1, bx2);
        if (crossX > minX && crossX < maxX && crossY > minY && crossY < maxY) {
          return true;
        }
      }
    } else {
      // New bridge is horizontal
      if (bx1 === bx2) {
        // Existing bridge is vertical
        const crossX = bx1;
        const crossY = from.y;
        const minX = Math.min(from.x, to.x);
        const maxX = Math.max(from.x, to.x);
        const minY = Math.min(by1, by2);
        const maxY = Math.max(by1, by2);
        if (crossY > minY && crossY < maxY && crossX > minX && crossX < maxX) {
          return true;
        }
      }
    }
  }
  return false;
}

// Compute current bridge counts per island
export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) {
    counts.set(isl.id, 0);
  }

  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const x1 = parts[0], y1 = parts[1], x2 = parts[2], y2 = parts[3];

    for (const isl of islands) {
      if ((isl.x === x1 && isl.y === y1) || (isl.x === x2 && isl.y === y2)) {
        counts.set(isl.id, (counts.get(isl.id) || 0) + count);
      }
    }
  }
  return counts;
}

// Check if adding delta bridges between from and to is valid
export function canAddBridge(islands, bridges, from, to, delta) {
  // Check adjacency
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: "Cannot connect non-adjacent islands" };
  }

  const key = bridgeKey(from, to);
  const current = bridges.get(key) || 0;
  const newCount = current + delta;

  // Check max 2
  if (newCount > 2) {
    return { valid: false, error: "Max 2 bridges per pair" };
  }

  // Check island capacity
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) || 0;
  const toCount = counts.get(to.id) || 0;

  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: "Island would exceed its number" };
  }

  // Check crossing (only if adding)
  if (delta > 0 && current === 0) {
    if (wouldCross(islands, bridges, from, to)) {
      return { valid: false, error: "Bridges would cross" };
    }
  }

  return { valid: true, error: null };
}

// Check connectivity: all islands with at least one bridge are connected
export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  // Build adjacency from bridges
  const adj = new Map();
  for (const isl of islands) {
    adj.set(isl.id, []);
  }

  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    const x1 = parts[0], y1 = parts[1], x2 = parts[2], y2 = parts[3];

    let id1 = null, id2 = null;
    for (const isl of islands) {
      if (isl.x === x1 && isl.y === y1) id1 = isl.id;
      if (isl.x === x2 && isl.y === y2) id2 = isl.id;
    }
    if (id1 !== null && id2 !== null) {
      adj.get(id1).push(id2);
      adj.get(id2).push(id1);
    }
  }

  // BFS from first island
  const visited = new Set();
  const queue = [islands[0].id];
  visited.add(islands[0].id);

  while (queue.length > 0) {
    const curr = queue.shift();
    for (const neighbor of (adj.get(curr) || [])) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }

  return visited.size === islands.length;
}

// Check if puzzle is solved
export function isVictory(islands, bridges) {
  // Check all islands have exact count
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) || 0) !== isl.value) return false;
  }

  // Check no bridges cross
  const bridgeList = [];
  for (const [key, count] of bridges.entries()) {
    if (count === 0) continue;
    const parts = key.split(',').map(Number);
    bridgeList.push({ x1: parts[0], y1: parts[1], x2: parts[2], y2: parts[3] });
  }

  for (let i = 0; i < bridgeList.length; i++) {
    for (let j = i + 1; j < bridgeList.length; j++) {
      const a = bridgeList[i];
      const b = bridgeList[j];
      // One horizontal, one vertical
      if (a.x1 === a.x2 && b.y1 === b.y2) {
        // a vertical, b horizontal
        const crossX = a.x1;
        const crossY = b.y1;
        if (crossX > Math.min(b.x1, b.x2) && crossX < Math.max(b.x1, b.x2) &&
            crossY > Math.min(a.y1, a.y2) && crossY < Math.max(a.y1, a.y2)) {
          return false;
        }
      } else if (a.y1 === a.y2 && b.x1 === b.x2) {
        // a horizontal, b vertical
        const crossX = b.x1;
        const crossY = a.y1;
        if (crossX > Math.min(a.x1, a.x2) && crossX < Math.max(a.x1, a.x2) &&
            crossY > Math.min(b.y1, b.y2) && crossY < Math.max(b.y1, b.y2)) {
          return false;
        }
      }
    }
  }

  // Check connectivity
  return checkConnectivity(islands, bridges);
}
