import React, { useState, useCallback, useEffect, useRef } from 'react';
import { puzzles } from './data/puzzles.js';
import {
  bridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID = 40;
const ISLAND_RADIUS = 16;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(null);
  const [error, setError] = useState(null);
  const [victory, setVictory] = useState(false);
  const [kbMode, setKbMode] = useState(false);
  const svgRef = useRef(null);

  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  // Reset when puzzle changes
  const resetGame = useCallback(() => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(null);
    setError(null);
    setVictory(false);
    setKbMode(false);
  }, []);

  const handlePuzzleChange = (e) => {
    setPuzzleIndex(Number(e.target.value));
    resetGame();
  };

  const handleReset = () => {
    resetGame();
  };

  // Try to toggle bridge between two islands
  const toggleBridge = useCallback((fromIsland, toIsland, forceRemove = false) => {
    const key = bridgeKey(fromIsland, toIsland);
    const current = bridges.get(key) || 0;

    if (forceRemove) {
      // Right-click: remove entirely
      if (current > 0) {
        const newBridges = new Map(bridges);
        newBridges.delete(key);
        setBridges(newBridges);
        setError(null);
        // Check victory
        if (isVictory(islands, newBridges)) {
          setVictory(true);
        } else {
          setVictory(false);
        }
      }
      return;
    }

    // Cycle: none(0) -> single(1) -> double(2) -> none(0)
    if (current === 2) {
      // Remove bridge (go to 0)
      const newBridges = new Map(bridges);
      newBridges.delete(key);
      setBridges(newBridges);
      setError(null);
      if (isVictory(islands, newBridges)) {
        setVictory(true);
      } else {
        setVictory(false);
      }
      return;
    }

    // Try to add one bridge
    const result = canAddBridge(islands, bridges, fromIsland, toIsland, 1);
    if (!result.valid) {
      setError(result.error);
      return;
    }

    const newBridges = new Map(bridges);
    newBridges.set(key, current + 1);
    setBridges(newBridges);
    setError(null);
    if (isVictory(islands, newBridges)) {
      setVictory(true);
    } else {
      setVictory(false);
    }
  }, [bridges, islands]);

  // Mouse click on island
  const handleIslandClick = useCallback((island, e) => {
    e.preventDefault();
    const isRightClick = e.type === 'contextmenu' || e.ctrlKey;

    if (selectedIsland === null) {
      if (!isRightClick) {
        setSelectedIsland(island);
        setError(null);
      }
    } else {
      if (selectedIsland.id === island.id) {
        // Clicking same island deselects
        setSelectedIsland(null);
        return;
      }
      if (isRightClick) {
        toggleBridge(selectedIsland, island, true);
      } else {
        toggleBridge(selectedIsland, island, false);
      }
      setSelectedIsland(null);
    }
  }, [selectedIsland, toggleBridge]);

  // Right-click on island
  const handleIslandRightClick = useCallback((island, e) => {
    e.preventDefault();
    if (selectedIsland !== null && selectedIsland.id !== island.id) {
      toggleBridge(selectedIsland, island, true);
      setSelectedIsland(null);
    }
  }, [selectedIsland, toggleBridge]);

  // Keyboard handling
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        setSelectedIsland(null);
        setKbMode(false);
        setCursorIslandId(null);
        return;
      }

      if (e.key === 'ArrowUp' || e.key === 'ArrowDown' ||
          e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
        e.preventDefault();
        setKbMode(true);

        const currentId = cursorIslandId !== null ? cursorIslandId : (islands.length > 0 ? islands[0].id : null);
        if (currentId === null) return;

        const currentIsland = islands.find(i => i.id === currentId);
        if (!currentIsland) return;

        // Find nearest island in direction
        let candidates = [];
        for (const isl of islands) {
          if (isl.id === currentId) continue;
          if (e.key === 'ArrowUp' && isl.y < currentIsland.y) candidates.push(isl);
          if (e.key === 'ArrowDown' && isl.y > currentIsland.y) candidates.push(isl);
          if (e.key === 'ArrowLeft' && isl.x < currentIsland.x) candidates.push(isl);
          if (e.key === 'ArrowRight' && isl.x > currentIsland.x) candidates.push(isl);
        }

        if (candidates.length > 0) {
          // Sort by distance
          candidates.sort((a, b) => {
            const da = Math.abs(a.x - currentIsland.x) + Math.abs(a.y - currentIsland.y);
            const db = Math.abs(b.x - currentIsland.x) + Math.abs(b.y - currentIsland.y);
            return da - db;
          });
          setCursorIslandId(candidates[0].id);
        }
        return;
      }

      if (e.key === 'Enter') {
        if (!kbMode || cursorIslandId === null) return;
        e.preventDefault();

        const cursorIsland = islands.find(i => i.id === cursorIslandId);
        if (!cursorIsland) return;

        if (selectedIsland === null) {
          setSelectedIsland(cursorIsland);
          setError(null);
        } else {
          if (selectedIsland.id === cursorIsland.id) {
            setSelectedIsland(null);
          } else {
            toggleBridge(selectedIsland, cursorIsland, false);
            setSelectedIsland(null);
          }
        }
        return;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cursorIslandId, kbMode, selectedIsland, islands, toggleBridge]);

  // Render bridges as line elements
  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges.entries()) {
      if (count === 0) continue;
      const parts = key.split(',').map(Number);
      const x1 = parts[0] * GRID;
      const y1 = parts[1] * GRID;
      const x2 = parts[2] * GRID;
      const y2 = parts[3] * GRID;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={x1} y1={y1} x2={x2} y2={y2}
            stroke="#0f0"
            strokeWidth="2"
          />
        );
      } else if (count === 2) {
        // Two parallel lines
        const isHorizontal = (parts[1] === parts[3]);
        const offset = 4;
        if (isHorizontal) {
          lines.push(
            <line
              key={key + '_a'}
              x1={x1} y1={y1 - offset} x2={x2} y2={y2 - offset}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
          lines.push(
            <line
              key={key + '_b'}
              x1={x1} y1={y1 + offset} x2={x2} y2={y2 + offset}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
        } else {
          lines.push(
            <line
              key={key + '_a'}
              x1={x1 - offset} y1={y1} x2={x2 - offset} y2={y2}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
          lines.push(
            <line
              key={key + '_b'}
              x1={x1 + offset} y1={y1} x2={x2 + offset} y2={y2}
              stroke="#0f0"
              strokeWidth="2"
            />
          );
        }
      }
    }
    return lines;
  };

  // Render islands as circles with numbers
  const renderIslands = () => {
    return islands.map((isl) => {
      const px = isl.x * GRID;
      const py = isl.y * GRID;
      const isSelected = selectedIsland && selectedIsland.id === isl.id;

      return (
        <g key={isl.id}>
          <circle
            cx={px}
            cy={py}
            r={ISLAND_RADIUS}
            fill="black"
            stroke={isSelected ? "#ff0" : "#0f0"}
            strokeWidth={isSelected ? 3 : 2}
            style={{ cursor: 'pointer' }}
            onClick={(e) => handleIslandClick(isl, e)}
            onContextMenu={(e) => handleIslandRightClick(isl, e)}
          />
          <text
            x={px}
            y={py}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="monospace"
            style={{ pointerEvents: 'none' }}
          >
            {isl.value}
          </text>
        </g>
      );
    });
  };

  // Render keyboard cursor (rect, not circle)
  const renderCursor = () => {
    if (!kbMode || cursorIslandId === null) return null;
    const isl = islands.find(i => i.id === cursorIslandId);
    if (!isl) return null;
    const px = isl.x * GRID;
    const py = isl.y * GRID;
    const size = ISLAND_RADIUS + 6;
    return (
      <rect
        x={px - size}
        y={py - size}
        width={size * 2}
        height={size * 2}
        fill="none"
        stroke="#ff0"
        strokeWidth="2"
        strokeDasharray="4,2"
        style={{ pointerEvents: 'none' }}
      />
    );
  };

  return (
    <div style={{ margin: 0, padding: 0 }}>
      <div style={{ padding: '8px', display: 'flex', gap: '12px', alignItems: 'center' }}>
        <select value={puzzleIndex} onChange={handlePuzzleChange}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', padding: '4px' }}>
          {puzzles.map((p, i) => (
            <option key={p.id} value={i}>{p.name}</option>
          ))}
        </select>
        <button onClick={handleReset}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace', padding: '4px 8px', cursor: 'pointer' }}>
          Reset
        </button>
        {error && <span className="error-message" style={{ color: '#f00', fontFamily: 'monospace' }}>{error}</span>}
        {victory && <span className="victory-banner" style={{ color: '#0f0', fontFamily: 'monospace', fontSize: '20px', fontWeight: 'bold' }}>SOLVED!</span>}
      </div>
      <svg
        ref={svgRef}
        width={800}
        height={600}
        style={{ display: 'block', background: 'black' }}
        onContextMenu={(e) => e.preventDefault()}
      >
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
